class Solution {
public:
    int minMovesToMakePalindrome(string s) {
        int n = s.size();
        int res = 0;
        for (int i = 0; i < n / 2; i++) {
            int j = n - 1 - i;
            if (s[i] == s[j]) continue;
            int k = j - 1;
            while (k > i && s[k] != s[i]) k--;
            res += j - k;
            while (k > i) {
                swap(s[k], s[k + 1]);
                k--;
            }
        }
        return res;
    }
};
